15	//----------------------------------------------------------------------------
16	// Package: coralnpu_test_pkg
17	// Description: Package for the CoralNPU UVM tests and sequences.
18	//----------------------------------------------------------------------------
19	package coralnpu_test_pkg;
20	
21	  import uvm_pkg::*;
22	  `include "uvm_macros.svh"
23	
24	  // Import required packages
25	  import transaction_item_pkg::*;
26	  import coralnpu_env_pkg::*;
27	  import coralnpu_axi_master_agent_pkg::*;
28	  import coralnpu_irq_agent_pkg::*;
29	
30	  //--------------------------------------------------------------------------
31	  // Sequence: coralnpu_kickoff_write_seq
32	  //--------------------------------------------------------------------------
33	  class coralnpu_kickoff_write_seq extends uvm_sequence #(axi_transaction);
34	    `uvm_object_utils(coralnpu_kickoff_write_seq)
35	
36	    bit [31:0] entry_point = 0;
37	
38	    function new(string name = "coralnpu_kickoff_write_seq");
39	        super.new(name);
40	    endfunction
41	
42	    virtual task body();
43	      axi_transaction req;
44	      `uvm_info(get_type_name(), "Starting kickoff writes", UVM_MEDIUM)
45	      // 1. Write PC address to 0x00030004
46	      req = axi_transaction::type_id::create("req_pc");
47	      start_item(req);
48	      req.txn_type = AXI_WRITE;
49	      req.addr = 32'h00030004;
50	      req.len  = 0;
51	      req.size = 2; // 4 bytes
52	      req.burst = AXI_BURST_INCR;
53	      req.id = 0;
54	      req.prot = 3'b000;
55	      req.data.delete();
56	      req.strb.delete();
57	      // Data must be shifted to lanes [63:32] for address 0x...4 on 128-bit bus
58	      req.data.push_back(128'(entry_point) << 32);
59	      req.strb.push_back(16'h00F0); // Enable bytes 4-7
60	      finish_item(req);
61	      `uvm_info(get_type_name(),
62	                $sformatf("Kickoff Write 1 (PC Data=0x%h) sent to addr 0x%h",
63	                          req.data[0], req.addr), UVM_LOW)
64	
65	      // 2. Write Clock Gate Release
66	      req = axi_transaction::type_id::create("req_clk_gate");
67	      start_item(req);
68	      req.txn_type = AXI_WRITE;
69	      req.addr = 32'h00030000;
70	      req.len  = 0;
71	      req.size = $clog2(32/8);
72	      req.burst = AXI_BURST_INCR;
73	      req.id = 0;
74	      req.prot = 3'b000;
75	      req.data.delete();
76	      req.strb.delete();
77	      req.data.push_back(128'h1);
78	      req.strb.push_back(16'h000F); // Strobe for lower 4 bytes
79	      finish_item(req);
80	      `uvm_info(get_type_name(),
81	                $sformatf("Kickoff Write 2 (ClkGate Data=0x%h) sent to addr 0x%h",
82	                          req.data[0], req.addr), UVM_LOW)
83	
84	      // 3. Write Reset Release
85	      req = axi_transaction::type_id::create("req_reset");
86	      start_item(req);
87	      req.txn_type = AXI_WRITE;
88	      req.addr = 32'h00030000;
89	      req.len  = 0;
90	      req.size = $clog2(32/8);
91	      req.burst = AXI_BURST_INCR;
92	      req.id = 0;
93	      req.prot = 3'b000;
94	      req.data.delete();
95	      req.strb.delete();
96	      req.data.push_back(128'h0);
97	      req.strb.push_back(16'h000F); // Strobe for lower 4 bytes
98	      finish_item(req);
99	      `uvm_info(get_type_name(),
100	                $sformatf("Kickoff Write 3 (Reset Data=0x%h) sent to addr 0x%h",
101	                          req.data[0], req.addr), UVM_LOW)
102	      `uvm_info(get_type_name(), "Finished kickoff writes", UVM_MEDIUM)
103	    endtask
104	  endclass
105	
106	  class coralnpu_pulse_irq_seq extends uvm_sequence #(irq_transaction);
107	    `uvm_object_utils(coralnpu_pulse_irq_seq);
108	
109	    function new(string name = "coralnpu_pulse_irq_seq");
110	        super.new(name);
111	    endfunction
112	
113	    virtual task body();
114	        irq_transaction req;
115	        coralnpu_irq_agent_pkg::coralnpu_irq_sequencer irq_sqr;
116	
117	        if (!$cast(irq_sqr, m_sequencer)) begin
118	           `uvm_fatal(get_type_name(), "Failed to cast m_sequencer to coralnpu_irq_sequencer")
119	        end
120	
121	        `uvm_info(get_type_name(), "Starting IRQ pulse", UVM_MEDIUM)
122	
123	        req = irq_transaction::type_id::create("req_irq_high");
124	        start_item(req);
125	        req.drive_irq = 1;
126	        req.irq_level = 1;
127	        finish_item(req);
128	        `uvm_info(get_type_name(), "req_irq_high sent", UVM_LOW)
129	
130	        repeat (10) @(irq_sqr.vif.tb_ctrl_cb);
131	
132	        req = irq_transaction::type_id::create("req_irq_low");
133	        start_item(req);
134	        req.drive_irq = 1;
135	        req.irq_level = 0;
136	        finish_item(req);
137	        `uvm_info(get_type_name(), "req_irq_low sent", UVM_LOW)
138	    endtask
139	  endclass
140	
141	  //--------------------------------------------------------------------------
142	  // Class: coralnpu_base_test
143	  //--------------------------------------------------------------------------
144	  class coralnpu_base_test extends uvm_test;
145	    `uvm_component_utils(coralnpu_base_test)
146	
147	    coralnpu_env env;
148	    time   test_timeout = 20_000_000ns;
149	
150	    protected bit test_passed = 1'b0;
151	    protected bit test_timed_out = 1'b0;
152	    protected bit dut_halted_flag = 1'b0;
153	    protected bit dut_faulted_flag = 1'b0;
154	    protected bit tohost_written_flag = 1'b0;
155	    protected bit spike_enabled = 1'b0;
156	    protected logic [127:0] final_tohost_data;
157	
158	    virtual coralnpu_irq_if.DUT_IRQ_PORT irq_vif;
159	    uvm_event tohost_written_event;
160	    uvm_event test_start_event;
161	    time clk_period;
162	    int unsigned entry_point = 0;
163	
164	    function new(string name = "coralnpu_base_test", uvm_component parent = null);
165	      super.new(name, parent);
166	    endfunction
167	
168	    virtual function void build_phase(uvm_phase phase);
169	      string test_elf;
170	      string timeout_str;
171	      string entry_point_str;
172	      int timeout_int;
173	      int unsigned initial_misa_value;
174	      uvm_cmdline_processor clp = uvm_cmdline_processor::get_inst();
175	
176	      super.build_phase(phase);
177	      `uvm_info(get_type_name(), "Build phase starting", UVM_MEDIUM)
178	      if ($test$plusargs("SPIKE_LOG")) begin
179	        spike_enabled = 1'b1;
180	      end
181	
182	      if (!clp.get_arg_value("+TEST_ELF=", test_elf)) begin
183	        `uvm_fatal(get_type_name(), "+TEST_ELF plusarg not specified.")
184	      end
185	
186	      if (clp.get_arg_value("+ENTRY_POINT=", entry_point_str)) begin
187	        if ($sscanf(entry_point_str, "'h%h", entry_point) != 1 &&
188	            $sscanf(entry_point_str, "0x%h", entry_point) != 1 &&
189	            $sscanf(entry_point_str, "%d", entry_point) != 1) begin
190	           `uvm_warning(get_type_name(),
191	             $sformatf("Invalid +ENTRY_POINT format: %s. Using default 0.", entry_point_str))
192	        end else begin
193	           `uvm_info(get_type_name(),
194	             $sformatf("Using entry point: 0x%h", entry_point), UVM_MEDIUM)
195	        end
196	      end
197	
198	      if (clp.get_arg_value("+TEST_TIMEOUT=", timeout_str)) begin
199	        if ($sscanf(timeout_str, "%d", timeout_int) == 1 && timeout_int > 0)
200	        begin
201	           test_timeout = timeout_int * 1ns;
202	           `uvm_info(get_type_name(),
203	                     $sformatf("Using custom timeout: %t", test_timeout),
204	                     UVM_MEDIUM)
205	        end else `uvm_warning(get_type_name(),
206	                      $sformatf("Invalid +TEST_TIMEOUT value: %s", timeout_str))
207	      end
208	
209	      begin
210	        string misa_value_str;
211	        if (clp.get_arg_value("+MISA_VALUE=", misa_value_str)) begin
212	          if ($sscanf(misa_value_str, "'h%h", initial_misa_value) != 1) begin
213	            `uvm_fatal(get_type_name(),
214	              "Invalid +MISA_VALUE format. Use hex format (e.g., 'h40201120).")
215	          end
216	        end else begin
217	          initial_misa_value = 32'h40201120;
218	        end
219	      end
220	
221	      env = coralnpu_env::type_id::create("env", this);
222	
223	      uvm_config_db#(string)::set(this, "*.m_cosim_checker",
224	                                  "elf_file_for_iss", test_elf);
225	      uvm_config_db#(int unsigned)::set(this, "*.m_cosim_checker",
226	                                        "initial_misa_value", initial_misa_value);
227	
228	      // Get the event handle that was created and set by tb_top
229	      if (!uvm_config_db#(uvm_event)::get(this, "",
230	          "tohost_written_event", tohost_written_event)) begin
231	        `uvm_fatal(get_type_name(), "tohost_written_event handle not found!")
232	      end
233	
234	      if (!uvm_config_db#(virtual coralnpu_irq_if.DUT_IRQ_PORT)::get(this, "",
235	          "irq_vif", irq_vif))
236	        `uvm_fatal(get_type_name(), "IRQ VIF 'irq_vif' not found")
237	      if (irq_vif == null)
238	        `uvm_fatal(get_type_name(), "IRQ VIF 'irq_vif' is null")
239	
240	      if (!uvm_config_db#(time)::get(this, "", "clk_period", clk_period))
241	        `uvm_fatal(get_type_name(), "clk_period not found in config_db")
242	
243	      if (!uvm_config_db#(uvm_event)::get(this, "", "test_start_event", test_start_event)) begin
244	        `uvm_fatal(get_type_name(), "test_start_event handle not found!")
245	      end
246	
247	      `uvm_info(get_type_name(), "Build phase finished", UVM_MEDIUM)
248	    endfunction
249	
250	    virtual task run_phase(uvm_phase phase);
251	      coralnpu_kickoff_write_seq kickoff_seq;
252	      coralnpu_pulse_irq_seq pulse_irq_seq;
253	      phase.raise_objection(this, "Base test running");
254	
255	      // Memory is loaded by $readmemh in tb_top before run phase starts.
256	
257	      `uvm_info(get_type_name(), "Waiting for reset deassertion...", UVM_MEDIUM)
258	      @(posedge irq_vif.clk iff irq_vif.resetn == 1'b1);
259	      `uvm_info(get_type_name(), "Reset deasserted.", UVM_MEDIUM)
260	
261	      test_start_event.trigger();
262	
263	      kickoff_seq = coralnpu_kickoff_write_seq::type_id::create("kickoff_seq");
264	      kickoff_seq.entry_point = entry_point;
265	      kickoff_seq.start(env.m_master_agent.sequencer);
266	
267	      `uvm_info(get_type_name(), "Waiting for completion or timeout...",
268	                UVM_MEDIUM)
269	      fork
270	        begin // Wait for tohost write
271	          tohost_written_event.wait_trigger();
272	          tohost_written_flag = 1'b1;
273	        end
274	        begin // Wait for DUT halted/faulted (backup termination)
275	          wait (irq_vif.halted == 1'b1 || irq_vif.fault == 1'b1);
276	          dut_halted_flag = irq_vif.halted;
277	          dut_faulted_flag = irq_vif.fault;
278	        end
279	        begin
280	          forever begin
281	            int delay;
282	
283	            wait (irq_vif.wfi == 1'b1);
284	            if (!std::randomize(delay) with {delay inside {[0:1000]};}) begin
285	              `uvm_error(get_type_name(), "Randomization of IRQ delay failed")
286	            end
287	            #(delay * 1ns);
288	            pulse_irq_seq = coralnpu_pulse_irq_seq::type_id::create("pulse_irq_seq");
289	            pulse_irq_seq.start(env.m_irq_agent.sequencer);
290	          end
291	        end
292	        begin // Timeout mechanism
293	          #(test_timeout);
294	          test_timed_out = 1'b1;
295	        end
296	      join_any
297	      disable fork;
298	
299	      #(clk_period/2);
300	
301	      `uvm_info(get_type_name(), "Run phase finishing", UVM_MEDIUM)
302	      phase.drop_objection(this, "Base test finished");
303	    endtask
304	
305	    virtual function void report_phase(uvm_phase phase);
306	      logic [31:1] status_code;
307	      uvm_report_server rs = uvm_report_server::get_server();
308	      int error_count = rs.get_severity_count(UVM_ERROR);
309	      int fatal_count = rs.get_severity_count(UVM_FATAL);
310	
311	      super.report_phase(phase);
312	      if (tohost_written_flag) begin
313	        if (uvm_config_db#(logic [127:0])::get(this, "",
314	            "final_tohost_data", final_tohost_data)) begin
315	          status_code = final_tohost_data[31:1];
316	          if (status_code == 0) begin
317	            if (error_count == 0 && fatal_count == 0) begin
318	               test_passed = 1'b1;
319	               `uvm_info(get_type_name(),
320	                 "tohost write detected with PASS status (0).", UVM_LOW)
321	            end else begin
322	               test_passed = 1'b0;
323	               `uvm_error(get_type_name(), "tohost write detected with PASS status (0), but UVM errors occurred during simulation.")
324	            end
325	          end else begin
326	            test_passed = 1'b0;
327	            `uvm_error(get_type_name(),
328	              $sformatf("tohost write detected with FAIL status code: %0d",
329	                        status_code))
330	          end
331	        end else `uvm_error(get_type_name(),
332	                  "tohost event triggered, but final status not found!")
333	      end else if (dut_halted_flag && !dut_faulted_flag) begin
334	        `uvm_info(get_type_name(), "Test ended on DUT halt.", UVM_LOW)
335	        if (error_count == 0 && fatal_count == 0) begin
336	           test_passed = 1'b1;
337	        end else begin
338	           test_passed = 1'b0;
339	           `uvm_error(get_type_name(), "Test ended on DUT halt, but UVM errors occurred during simulation.")
340	        end
341	      end else if (dut_faulted_flag) begin
342	        if (rs.get_severity_count(UVM_ERROR) == 0 && rs.get_severity_count(UVM_FATAL) == 0) begin
343	            `uvm_info(get_type_name(), "Test ended on DUT fault, but no Co-Simulation mismatches were detected. Assuming consistent behavior (PASS).", UVM_LOW)
344	            test_passed = 1'b1;
345	        end else begin
346	            `uvm_info(get_type_name(), "Test ended on DUT fault with Co-Sim mismatches (FAIL).", UVM_LOW)
347	            test_passed = 1'b0;
348	        end
349	      end else if (test_timed_out) begin
350	        if (spike_enabled) begin
351	            `uvm_error(get_type_name(), $sformatf("Test timed out after %t. Spike was enabled, so this is a failure (divergence/stall).", test_timeout))
352	            test_passed = 1'b0;
353	        end else if (rs.get_severity_count(UVM_ERROR) == 0 && rs.get_severity_count(UVM_FATAL) == 0) begin
354	            `uvm_info(get_type_name(), $sformatf("Test timed out after %t, but no Co-Simulation mismatches were detected. Assuming PASS.", test_timeout), UVM_LOW)
355	            test_passed = 1'b1;
356	        end else begin
357	            `uvm_error(get_type_name(), $sformatf("Test timed out after %t with errors/mismatches.", test_timeout))
358	            test_passed = 1'b0;
359	        end
360	      end else begin
361	        `uvm_error(get_type_name(), "Test ended with no clear pass/fail.")
362	        test_passed = 1'b0;
363	      end
364	
365	      if(test_passed) `uvm_info(get_type_name(), "** UVM TEST PASSED **",
366	                                UVM_NONE)
367	      else `uvm_error(get_type_name(), "** UVM TEST FAILED **")
368	    endfunction
369	
370	  endclass
371	
372	  //--------------------------------------------------------------------------
373	  // Class: coralnpu_regression_test
374	  //--------------------------------------------------------------------------
375	  import "DPI-C" function void sram_load_elf(input string filename);
376	  import "DPI-C" function void sram_clear();
377	
378	  class coralnpu_regression_test extends coralnpu_base_test;
379	    `uvm_component_utils(coralnpu_regression_test)
380	
381	    int total_tests = 0;
382	    int passed_tests = 0;
383	    int failed_tests = 0;
384	
385	    function new(string name = "coralnpu_regression_test", uvm_component parent = null);
386	      super.new(name, parent);
387	    endfunction
388	
389	    virtual function void build_phase(uvm_phase phase);
390	      uvm_report_server rs;
391	      super.build_phase(phase);
392	      rs = uvm_report_server::get_server();
393	      rs.set_max_quit_count(0);
394	    endfunction
395	
396	    virtual task run_phase(uvm_phase phase);
397	      string regression_list_file;
398	      int fd;
399	      string current_elf;
400	      logic [31:0] current_tohost;
401	      int current_entry;
402	      int current_timeout;
403	      string current_spike_log;
404	      string current_target;
405	      string line;
406	
407	      uvm_event pulse_reset_event;
408	      coralnpu_kickoff_write_seq kickoff_seq;
409	      coralnpu_pulse_irq_seq pulse_irq_seq;
410	
411	      phase.raise_objection(this, "Regression running");
412	
413	      if (!uvm_config_db#(uvm_event)::get(this, "", "test_start_event", test_start_event)) begin
414	        `uvm_fatal(get_type_name(), "test_start_event handle not found!")
415	      end
416	
417	      if (!uvm_config_db#(uvm_event)::get(this, "", "pulse_reset_event", pulse_reset_event)) begin
418	        `uvm_fatal(get_type_name(), "pulse_reset_event handle not found!")
419	      end
420	
421	      if (!$value$plusargs("REGRESSION_LIST=%s", regression_list_file)) begin
422	        `uvm_fatal(get_type_name(), "+REGRESSION_LIST plusarg not specified.")
423	      end
424	
425	      fd = $fopen(regression_list_file, "r");
426	      if (fd == 0) begin
427	        `uvm_fatal(get_type_name(), $sformatf("Failed to open %s", regression_list_file))
428	      end
429	
430	      while (!$feof(fd)) begin
431	        if ($fgets(line, fd)) begin
432	          if (line == "" || line.substr(0,0) == "#") continue;
433	
434	          // Format: ELF TOHOST ENTRY TIMEOUT SPIKE_LOG TARGET
435	          if ($sscanf(line, "%s %h %h %d %s %s", current_elf, current_tohost, current_entry, current_timeout, current_spike_log, current_target) == 6) begin
436	            `uvm_info(get_type_name(), $sformatf("--- STARTING TEST: %s ---", current_target), UVM_NONE)
437	            total_tests++;
438	
439	            // Reset state for new test
440	            test_passed = 1'b0;
441	            test_timed_out = 1'b0;
442	            dut_halted_flag = 1'b0;
443	            dut_faulted_flag = 1'b0;
444	            tohost_written_flag = 1'b0;
445	            tohost_written_event.reset();
446	            test_timeout = current_timeout * 1ns;
447	            entry_point = current_entry;
448	            if (current_spike_log != "NONE") spike_enabled = 1'b1;
449	            else spike_enabled = 1'b0;
450	
451	            // Teardown and Re-load
452	            sram_clear();
453	            sram_load_elf(current_elf);
454	
455	            // Pass configuration to checker
456	            uvm_config_db#(string)::set(null, "*", "current_test_elf", current_elf);
457	            uvm_config_db#(string)::set(null, "*", "current_spike_log", current_spike_log);
458	            uvm_config_db#(logic [31:0])::set(null, "*", "tohost_addr", current_tohost);
459	            uvm_config_db#(bit)::set(null, "*", "cosim_mismatch_detected", 0);
460	
461	            // Pulse Reset for tests AFTER the first one
462	            if (total_tests > 1) begin
463	               pulse_reset_event.trigger();
464	               @(posedge irq_vif.clk iff irq_vif.resetn == 1'b0);
465	            end
466	            @(posedge irq_vif.clk iff irq_vif.resetn == 1'b1);
467	
468	            // Ensure DUT has finished clearing internal halt/fault state
469	            if (irq_vif.halted == 1'b1 || irq_vif.fault == 1'b1) begin
470	               @(posedge irq_vif.clk iff (irq_vif.halted == 1'b0 && irq_vif.fault == 1'b0));
471	            end
472	
473	            test_start_event.trigger();
474	
475	            kickoff_seq = coralnpu_kickoff_write_seq::type_id::create("kickoff_seq");
476	            kickoff_seq.entry_point = entry_point;
477	            kickoff_seq.start(env.m_master_agent.sequencer);
478	
479	            `uvm_info(get_type_name(), "Waiting for completion or timeout...", UVM_MEDIUM)
480	            fork
481	              begin // Wait for tohost write
482	                tohost_written_event.wait_trigger();
483	                tohost_written_flag = 1'b1;
484	              end
485	              begin // Wait for DUT halted/faulted (backup termination)
486	                wait (irq_vif.halted == 1'b1 || irq_vif.fault == 1'b1);
487	                dut_halted_flag = irq_vif.halted;
488	                dut_faulted_flag = irq_vif.fault;
489	              end
490	              begin
491	                forever begin
492	                  int delay;
493	                  wait (irq_vif.wfi == 1'b1);
494	                  if (!std::randomize(delay) with {delay inside {[0:1000]};}) begin
495	                    `uvm_error(get_type_name(), "Randomization of IRQ delay failed")
496	                  end
497	                  #(delay * 1ns);
498	                  pulse_irq_seq = coralnpu_pulse_irq_seq::type_id::create("pulse_irq_seq");
499	                  pulse_irq_seq.start(env.m_irq_agent.sequencer);
500	                  wait (irq_vif.wfi == 1'b0);
501	                end
502	              end
503	              begin // Timeout mechanism
504	                #(test_timeout);
505	                test_timed_out = 1'b1;
506	              end
507	            join_any
508	            disable fork;
509	
510	            #(clk_period/2);
511	
512	            evaluate_batch_test_result(current_target);
513	
514	            `uvm_info(get_type_name(), $sformatf("--- FINISHED TEST: %s ---\n", current_target), UVM_NONE)
515	          end
516	        end
517	      end
518	      $fclose(fd);
519	
520	      `uvm_info(get_type_name(), $sformatf("REGRESSION COMPLETE. Passed: %0d/%0d", passed_tests, total_tests), UVM_NONE)
521	      phase.drop_objection(this, "Regression finished");
522	    endtask
523	
524	    virtual function void evaluate_batch_test_result(string target_name);
525	      logic [31:1] status_code;
526	      bit mismatch;
527	      if (!uvm_config_db#(bit)::get(null, "*", "cosim_mismatch_detected", mismatch)) mismatch = 0;
528	
529	      if (tohost_written_flag) begin
530	        if (uvm_config_db#(logic [127:0])::get(this, "", "final_tohost_data", final_tohost_data)) begin
531	          status_code = final_tohost_data[31:1];
532	          if (status_code == 0 && !mismatch) begin
533	            test_passed = 1'b1;
534	          end else begin
535	            test_passed = 1'b0;
536	            `uvm_info(get_type_name(), $sformatf("tohost code: %0d, mismatch: %0d", status_code, mismatch), UVM_NONE)
537	          end
538	        end else begin
539	            test_passed = 1'b0;
540	            `uvm_info(get_type_name(), "tohost triggered but no data", UVM_NONE)
541	        end
542	      end else if (dut_halted_flag && !dut_faulted_flag && !mismatch) begin
543	        test_passed = 1'b1;
544	      end else if (dut_faulted_flag && !mismatch) begin
545	        `uvm_info(get_type_name(), "Test ended on DUT fault, but no Co-Simulation mismatches were detected. Assuming consistent behavior (PASS).", UVM_LOW)
546	        test_passed = 1'b1;
547	      end else if (test_timed_out) begin
548	        if (spike_enabled) begin
549	            test_passed = 1'b0;
550	            `uvm_info(get_type_name(), "FAILED: Timeout with Spike enabled", UVM_NONE)
551	        end else if (!mismatch) begin
552	            `uvm_info(get_type_name(), "Test timed out, but no Co-Simulation mismatches were detected. Assuming PASS.", UVM_LOW)
553	            test_passed = 1'b1;
554	        end else begin
555	            test_passed = 1'b0;
556	            `uvm_info(get_type_name(), "FAILED: Timeout with co-sim mismatches", UVM_NONE)
557	        end
558	      end else if (mismatch) begin
559	        test_passed = 1'b0;
560	        `uvm_info(get_type_name(), "FAILED: Co-Simulation mismatch detected", UVM_NONE)
561	      end else begin
562	        test_passed = 1'b0;
563	        `uvm_info(get_type_name(), "FAILED: Unknown error or DUT fault with mismatches", UVM_NONE)
564	      end
565	
566	      if(test_passed) begin
567	         `uvm_info(get_type_name(), "** UVM TEST PASSED **", UVM_NONE)
568	         passed_tests++;
569	      end else begin
570	         `uvm_error(get_type_name(), "** UVM TEST FAILED **")
571	         failed_tests++;
572	      end
573	    endfunction
574	
575	    virtual function void report_phase(uvm_phase phase);
576	       if (failed_tests > 0) begin
577	          `uvm_info("REGRESSION_SUMMARY", $sformatf("%0d/%0d tests failed.", failed_tests, total_tests), UVM_NONE)
578	       end else begin
579	          `uvm_info("REGRESSION_SUMMARY", $sformatf("All %0d tests passed.", total_tests), UVM_NONE)
580	       end
581	    endfunction
582	
583	  endclass
584	
585	endpackage : coralnpu_test_pkg
586

