146	task rvv_scoreboard::rt_checker();
147	  rvs_transaction mdl_tr;
148	  rvs_transaction rvs_tr;
149	
150	  int        rt_vrf_num;
151	  reg_idx_t  rvs_rt_vrf_index , mdl_rt_vrf_index ;
152	  vrf_byte_t rvs_rt_vrf_byte_strobe, mdl_rt_vrf_byte_strobe;
153	  vrf_t      rvs_rt_vrf_bit_strobe,  mdl_rt_vrf_bit_strobe;
154	  vrf_t      rvs_rt_vrf_data  , mdl_rt_vrf_data  ;
155	
156	  string vreg_dut_val;
157	  string vreg_mdl_val;
158	  string mismatch_mark;
159	
160	  int        rt_xrf_num;
161	  reg_idx_t  rvs_rt_xrf_index, mdl_rt_xrf_index;
162	  xrf_t      rvs_rt_xrf_data , mdl_rt_xrf_data ;
163	  forever begin
164	    @(negedge rvs_if.clk);
165	    if(rt_queue_mdl.size() != rt_queue_rvs.size()) begin
166	      `uvm_fatal("RT_CHECKER","Retire inst number mismatch between DUT & MDL.");
167	    end
168	    while(rt_queue_rvs.size()>0 && rt_queue_mdl.size()>0) begin 
169	      rvs_tr = rt_queue_rvs.pop_front();
170	      mdl_tr = rt_queue_mdl.pop_front();
171	
172	      `uvm_info("RT_RECORDER", $sformatf("\nRetire check start. ====================================================================================================\n"),UVM_LOW)
173	      `uvm_info("RT_RECORDER", $sformatf("Got retire transaction from DUT:\n%s",rvs_tr.sprint()),UVM_LOW)
174	      `uvm_info("RT_RECORDER", $sformatf("Got retire transaction from MDL:\n%s",mdl_tr.sprint()),UVM_LOW)
175	
176	      // PC check
177	      // if(rvs_tr.pc !== mdl_tr.pc) begin
178	      //   `uvm_error("RT_CHECKER", $sformatf("Retire PC mismatch:\nDUT retired pc 0x%8x, \nMDL retired pc 0x%8x.", 
179	      //                                       rvs_tr.pc,
180	      //                                       mdl_tr.pc))
181	      // end
182	
183	      // VRF check
184	      if(rvs_tr.rt_vrf_index.size() != mdl_tr.rt_vrf_index.size()) begin
185	        `uvm_error("RT_CHECKER", $sformatf("Retire VRF quantity mismatch:\nDUT retired %0d vregs, \nMDL retired %0d vregs.", 
186	                                            rvs_tr.rt_vrf_index.size(),
187	                                            mdl_tr.rt_vrf_index.size()))
188	      end else begin
189	        rt_vrf_num = rvs_tr.rt_vrf_index.size();
190	        for(int i=0; i<rt_vrf_num; i++) begin
191	          rvs_rt_vrf_index  = rvs_tr.rt_vrf_index.pop_front();
192	          rvs_rt_vrf_byte_strobe = rvs_tr.rt_vrf_strobe.pop_front();
193	          rvs_rt_vrf_data   = rvs_tr.rt_vrf_data.pop_front();
194	          mdl_rt_vrf_index  = mdl_tr.rt_vrf_index.pop_front();
195	          mdl_rt_vrf_byte_strobe = mdl_tr.rt_vrf_strobe.pop_front();
196	          mdl_rt_vrf_data   = mdl_tr.rt_vrf_data.pop_front();
197	          // Since RTL use byte_strobe for retire, 
198	          //   MDL should generate byte_strobe, 
199	          //   and SCB also need to expand byte_strobe to bit_strobe to compare data.
200	          for(int bit_idx=0; bit_idx<`VLENB; bit_idx++) begin
201	            rvs_rt_vrf_bit_strobe[bit_idx*8 +: 8] = {8{rvs_rt_vrf_byte_strobe[bit_idx]}}; 
202	            mdl_rt_vrf_bit_strobe[bit_idx*8 +: 8] = {8{mdl_rt_vrf_byte_strobe[bit_idx]}}; 
203	          end 
204	          if(rvs_rt_vrf_index !== mdl_rt_vrf_index) begin
205	            `uvm_error("RT_CHECKER", $sformatf("Retire VRF index mismatch:\nDUT retired vrf[%0d],\nMDL retired vrf[%0d].", 
206	                                                rvs_rt_vrf_index, 
207	                                                mdl_rt_vrf_index));
208	          end else if(rvs_rt_vrf_byte_strobe !== mdl_rt_vrf_byte_strobe) begin
209	            vreg_dut_val = "0x";
210	            vreg_mdl_val = "0x";
211	            for(int i=`VLEN-1;i>=0;i-=16) begin
212	              vreg_dut_val = $sformatf("%s%4h_",vreg_dut_val,rvs_rt_vrf_byte_strobe[i-:16]);
213	              vreg_mdl_val = $sformatf("%s%4h_",vreg_mdl_val,mdl_rt_vrf_byte_strobe[i-:16]);
214	            end
215	            vreg_dut_val = vreg_dut_val.substr(0,vreg_dut_val.len()-2);
216	            vreg_mdl_val = vreg_mdl_val.substr(0,vreg_mdl_val.len()-2);
217	            `uvm_error("RT_CHECKER", $sformatf("Retire VRF strobe(bit) mismatch:\nDUT retired vrf_strobe[%0d] = %s,\nMDL retired vrf_strobe[%0d] = %s.", 
218	                                               rvs_rt_vrf_index, vreg_dut_val,
219	                                               mdl_rt_vrf_index, vreg_mdl_val));
220	          end else if((rvs_rt_vrf_bit_strobe & rvs_rt_vrf_data) !== (mdl_rt_vrf_bit_strobe & mdl_rt_vrf_data)) begin
221	            vreg_dut_val = "0x";
222	            vreg_mdl_val = "0x";
223	            mismatch_mark= "  ";
224	            for(int i=`VLEN-1;i>=0;i-=8) begin
225	              vreg_dut_val = $sformatf("%s%2h",vreg_dut_val,{rvs_rt_vrf_bit_strobe & rvs_rt_vrf_data}[i-:8]);
226	              vreg_mdl_val = $sformatf("%s%2h",vreg_mdl_val,{mdl_rt_vrf_bit_strobe & mdl_rt_vrf_data}[i-:8]);
227	              if({rvs_rt_vrf_bit_strobe & rvs_rt_vrf_data}[i-:8] !== {mdl_rt_vrf_bit_strobe & mdl_rt_vrf_data}[i-:8]) begin
228	                mismatch_mark = $sformatf("%s^^", mismatch_mark);
229	              end else begin
230	                mismatch_mark = $sformatf("%s  ", mismatch_mark);
231	              end
232	              if(i%16 == 7) begin
233	                vreg_dut_val = $sformatf("%s_",vreg_dut_val);
234	                vreg_mdl_val = $sformatf("%s_",vreg_mdl_val);
235	                mismatch_mark = $sformatf("%s ", mismatch_mark);
236	              end
237	            end
238	            vreg_dut_val = vreg_dut_val.substr(0,vreg_dut_val.len()-2);
239	            vreg_mdl_val = vreg_mdl_val.substr(0,vreg_mdl_val.len()-2);
240	            // `uvm_error("RT_CHECKER", $sformatf("Retire VRF mismatch:\nDUT retired vrf[%0d] = 0x%0x,\nMDL retired vrf[%0d] = 0x%0x.", 
241	            //                                     rvs_rt_vrf_index, (rvs_rt_vrf_bit_strobe & rvs_rt_vrf_data),
242	            //                                     mdl_rt_vrf_index, (mdl_rt_vrf_bit_strobe & mdl_rt_vrf_data)));
243	            `uvm_error("RT_CHECKER", {$sformatf("Retire VRF mismatch:\n"),
244	                                      $sformatf("DUT retired vrf[%2d] = %s\n",rvs_rt_vrf_index, vreg_dut_val),
245	                                      $sformatf("MDL retired vrf[%2d] = %s\n",mdl_rt_vrf_index, vreg_mdl_val), 
246	                                      $sformatf("mismatch_mark       = %s\n",mismatch_mark)});
247	          end else begin
248	            `uvm_info("RT_CHECKER", $sformatf("Retire vrf[%0d] check pass.",rvs_rt_vrf_index), UVM_LOW)
249	          end
250	        end
251	      end
252	
253	      // XRF check
254	      if(rvs_tr.rt_xrf_index.size() != mdl_tr.rt_xrf_index.size()) begin
255	        `uvm_error("RT_CHECKER", $sformatf("Retire XRF quantity mismatch:\nDUT retired %0d xregs,\nMDL retired %0d xregs.", 
256	                                            rvs_tr.rt_xrf_index.size(),
257	                                            mdl_tr.rt_xrf_index.size()))
258	      end else begin
259	        rt_xrf_num = rvs_tr.rt_xrf_index.size();
260	        for(int i=0; i<rt_xrf_num; i++) begin
261	          rvs_rt_xrf_index  = rvs_tr.rt_xrf_index.pop_front();
262	          rvs_rt_xrf_data   = rvs_tr.rt_xrf_data.pop_front();
263	          mdl_rt_xrf_index  = mdl_tr.rt_xrf_index.pop_front();
264	          mdl_rt_xrf_data   = mdl_tr.rt_xrf_data.pop_front();
265	          if(rvs_rt_xrf_index !== mdl_rt_xrf_index) begin
266	            `uvm_error("RT_CHECKER", $sformatf("Retire XRF index mismatch:\nDUT retired xrf[%0d],\nMDL retired xrf[%0d].", 
267	                                                rvs_rt_xrf_index, 
268	                                                mdl_rt_xrf_index));
269	          end else if(rvs_rt_xrf_data !== mdl_rt_xrf_data) begin
270	            `uvm_error("RT_CHECKER", $sformatf("Retire XRF mismatch:\nDUT retired xrf[%0d] = 0x%8x,\nMDL retired xrf[%0d] = 0x%8x.", 
271	                                                rvs_rt_xrf_index, rvs_rt_xrf_data,
272	                                                mdl_rt_xrf_index, mdl_rt_xrf_data));
273	          end else begin
274	            `uvm_info("RT_CHECKER", $sformatf("Retire xrf[%0d] check pass.",rvs_rt_xrf_index), UVM_LOW)
275	          end
276	        end
277	      end
278	
279	      // VXSAT check
280	      if(rvs_tr.vxsat_valid !== mdl_tr.vxsat_valid) begin
281	        `uvm_error("RT_CHECKER","RVV vxsat_valid mismatch with reference model.");
282	      end else if(rvs_tr.vxsat_valid === 1 && mdl_tr.vxsat_valid === 1) begin
283	        if(rvs_tr.vxsat !== mdl_tr.vxsat) begin
284	          `uvm_error("RT_CHECKER", $sformatf("Retire vxsat mismatch:\nDUT vxsat = %0d\nMDL vxsat = %0d",
285	                                              rvs_tr.vxsat,
286	                                              mdl_tr.vxsat));
287	        end else begin
288	          `uvm_info("RT_CHECKER", "Writeback vxsat check pass.", UVM_LOW)
289	        end
290	      end
291	
292	      // TRAP check
293	      if(rvs_tr.trap_occured !== mdl_tr.trap_occured) begin
294	        `uvm_error("RT_CHECKER","RVV trap_occured mismatch with reference model.");
295	      end else if(rvs_tr.trap_occured) begin
296	        if(rvs_tr.trap_vma !== mdl_tr.trap_vma) begin
297	          `uvm_error("RT_CHECKER","RVV trap_vma mismatch with reference model.");
298	        end else if(rvs_tr.trap_vta !== mdl_tr.trap_vta) begin
299	          `uvm_error("RT_CHECKER","RVV trap_vta mismatch with reference model.");
300	        end else if(rvs_tr.trap_vsew !== mdl_tr.trap_vsew) begin
301	          `uvm_error("RT_CHECKER","RVV trap_vsew mismatch with reference model."); 
302	        end else if(rvs_tr.trap_vlmul !== mdl_tr.trap_vlmul) begin
303	          `uvm_error("RT_CHECKER","RVV trap_vlmul mismatch with reference model.");
304	        end else if(rvs_tr.trap_vl !== mdl_tr.trap_vl) begin
305	          `uvm_error("RT_CHECKER","RVV trap_vl mismatch with reference model.");
306	        end else if(rvs_tr.trap_vstart !== mdl_tr.trap_vstart) begin
307	          `uvm_error("RT_CHECKER","RVV trap_vstart mismatch with reference model.");
308	        end else if(rvs_tr.trap_vxrm !== mdl_tr.trap_vxrm) begin
309	          `uvm_error("RT_CHECKER","RVV trap_vxrm mismatch with reference model.");
310	        end else begin
311	          `uvm_info("RT_CHECKER", "Trap check pass.", UVM_LOW)
312	        end 
313	      end
314	      `uvm_info("RT_RECORDER", $sformatf("\nRetire check done.  ====================================================================================================\n\n"),UVM_LOW)
315	    end
316	  end 
317	endtask: rt_checker 
318	
319	task rvv_scoreboard::vrf_checker();
320	  vrf_transaction mdl_tr;
321	  vrf_transaction rvs_tr;
322	  int err;
323	  string vreg_dut_val;
324	  string vreg_mdl_val;
325	  forever begin
326	    @(negedge rvs_if.clk); 
327	    err = 0;
328	    if(vrf_queue_rvs.size()>1 || vrf_queue_mdl.size()>1) begin
329	      `uvm_error("TB_ISSUE", "Got more than 1 vrf check request, please check the TB.");
330	    end
331	    if(vrf_queue_rvs.size()>0 && vrf_queue_mdl.size()>0) begin
332	      rvs_tr = vrf_queue_rvs.pop_front();
333	      mdl_tr = vrf_queue_mdl.pop_front();
334	      `uvm_info("VRF_RECORDER", $sformatf("\nVRF check start. ====================================================================================================\n"),UVM_HIGH)
335	      for(int idx=0; idx<32; idx++) begin
336	        vreg_dut_val = "0x";
337	        vreg_mdl_val = "0x";
338	        if(rvs_tr.vreg[idx] !== mdl_tr.vreg[idx]) begin
339	          for(int i=`VLEN-1;i>=0;i-=16) begin
340	            vreg_dut_val = $sformatf("%s%4h_",vreg_dut_val,rvs_tr.vreg[idx][i-:16]);
341	            vreg_mdl_val = $sformatf("%s%4h_",vreg_mdl_val,mdl_tr.vreg[idx][i-:16]);
342	          end
343	          vreg_dut_val = vreg_dut_val.substr(0,vreg_dut_val.len()-2);
344	          vreg_mdl_val = vreg_mdl_val.substr(0,vreg_mdl_val.len()-2);
345	          //`uvm_warning("VRF_RECORDER", $sformatf("VRF[%0d] value mismatch: \ndut = 0x%0h \nmdl = 0x%0h", idx, rvs_tr.vreg[idx], mdl_tr.vreg[idx]))
346	          //`uvm_error("VRF_CHECKER", $sformatf("VRF[%0d] value mismatch: \ndut = 0x%0h \nmdl = 0x%0h", idx, rvs_tr.vreg[idx], mdl_tr.vreg[idx]))
347	          `uvm_warning("VRF_RECORDER", $sformatf("VRF[%0d] value mismatch: \ndut = %s \nmdl = %s", idx, vreg_dut_val, vreg_mdl_val))
348	          `uvm_error("VRF_CHECKER", $sformatf("VRF[%0d] value mismatch: \ndut = %s \nmdl = %s", idx, vreg_dut_val, vreg_mdl_val))
349	          err++;
350	        end
351	        `uvm_info("VRF_RECORDER", $sformatf("VRF[%0d] value: \ndut = 0x%0h \nmdl = 0x%0h", idx, rvs_tr.vreg[idx], mdl_tr.vreg[idx]), UVM_HIGH)
352	      end
353	      if(!err) begin
354	        `uvm_info("VRF_CHECKER", "VRF check pass", UVM_LOW)
355	      end
356	      `uvm_info("VRF_RECORDER", $sformatf("\nVRF check done.  ====================================================================================================\n"),UVM_HIGH)
357	    end
358	  end
359	endtask: vrf_checker 
360	
361	task rvv_scoreboard::mem_access_checker();
362	  mem_transaction lsu_tr;
363	  mem_transaction mdl_tr;
364	  int err;
365	  forever begin
366	    @(negedge rvs_if.clk); 
367	    if(~rvs_if.rst_n) begin
368	      mem_queue_lsu.delete();
369	      mem_queue_mdl.delete();
370	      err=0;
371	    end else begin
372	    err = 0;
373	    while(mem_queue_mdl.size()>0) begin
374	      if(mem_queue_lsu.size()>0) begin
375	        lsu_tr = mem_queue_lsu.pop_front();
376	        mdl_tr = mem_queue_mdl.pop_front();
377	        `uvm_info("MEM_RECORDER", $sformatf("\nMEM check start. ====================================================================================================\n"),UVM_HIGH)
378	        `uvm_info("MEM_RECORDER", "lsu memory tr:", UVM_HIGH)
379	        `uvm_info("MEM_RECORDER", lsu_tr.sprint(), UVM_HIGH)
380	        `uvm_info("MEM_RECORDER", "mdl memory tr:", UVM_HIGH)
381	        `uvm_info("MEM_RECORDER", mdl_tr.sprint(), UVM_HIGH)
382	        if(lsu_tr.kind != mdl_tr.kind) begin
383	          `uvm_error("MEM_CHCKER", $sformatf("Memory access kind mismatch: lsu = %s, mdl = %s", lsu_tr.kind.name(), mdl_tr.kind.name()))
384	          err++;
385	        end else begin
386	          `uvm_info("MEM_CHCKER", $sformatf("Memory access kind: lsu = %s, mdl = %s", lsu_tr.kind.name(), mdl_tr.kind.name()), UVM_HIGH)
387	        end
388	        if(lsu_tr.addr != mdl_tr.addr) begin
389	          `uvm_error("MEM_CHCKER", $sformatf("Memory access addr mismatch: lsu = 0x%8x, mdl = 0x%8x", lsu_tr.addr, mdl_tr.addr))
390	          err++;
391	        end else begin
392	          `uvm_info("MEM_CHCKER", $sformatf("Memory access addr: lsu = 0x%8x, mdl = 0x%8x", lsu_tr.addr, mdl_tr.addr), UVM_HIGH)
393	        end
394	        if(lsu_tr.data !== mdl_tr.data) begin
395	          `uvm_error("MEM_CHCKER", $sformatf("Memory access data mismatch: lsu = 0x%2x, mdl = 0x%2x", lsu_tr.data, mdl_tr.data))
396	          err++;
397	        end else begin
398	          `uvm_info("MEM_CHCKER", $sformatf("Memory access data: lsu = 0x%2x, mdl = 0x%2x", lsu_tr.data, mdl_tr.data), UVM_HIGH)
399	        end
400	        `uvm_info("MEM_RECORDER", $sformatf("\nMEM check done.  ====================================================================================================\n"),UVM_HIGH)
401	      end else begin
402	        // Model will execute instruction only if DUT retires this inst.
403	        // If we changed how model work, please update while condition.
404	        `uvm_error("MEM_CHCKER", "MDL has accessed memory but LSU hasn't.")
405	      end
406	    end
407	    end
408	  end
409	  if(err == 0) begin
410	    `uvm_info("MEM_CHCKER", "Memory access check pass", UVM_LOW)
411	  end
412	endtask: mem_access_checker
413	
414	function void rvv_scoreboard::final_phase(uvm_phase phase);
415	  super.final_phase(phase);
416	
417	  if(!uvm_config_db#(int)::get(uvm_root::get(), "", "rvv_total_inst", this.rvv_total_inst)) begin
418	    `uvm_fatal(get_type_name(), "Fail to get rvv_total_inst!")
419	  end
420	  if(!uvm_config_db#(int)::get(uvm_root::get(), "", "rvv_excuted_inst", this.rvv_executed_inst)) begin
421	    `uvm_fatal(get_type_name(), "Fail to get rvv_executed_inst!")
422	  end
423	  if(!uvm_config_db#(int)::get(uvm_root::get(), "", "mdl_total_inst", this.mdl_total_inst)) begin
424	    `uvm_fatal(get_type_name(), "Fail to get mdl_total_inst!")
425	  end
426	  if(!uvm_config_db#(int)::get(uvm_root::get(), "", "mdl_excuted_inst", this.mdl_executed_inst)) begin
427	    `uvm_fatal(get_type_name(), "Fail to get mdl_executed_inst!")
428	  end
429	
430	  // Memory compare
431	  `uvm_info("FINAL_CHECK", "Checking memory...", UVM_LOW)
432	  foreach(test_top.env.lsu_agt.lsu_drv.mem.mem[idx]) begin
433	    if(test_top.env.lsu_agt.lsu_drv.mem.mem[idx] !== test_top.env.mdl.mem.mem[idx])
434	      `uvm_error("FINAL_CHECK", $sformatf("Memory mismatch: lsu_mem[0x%8x] = 0x%2x, mdl_mem[0x%8x] = 0x%2x.", idx, test_top.env.lsu_agt.lsu_drv.mem.mem[idx], idx, test_top.env.mdl.mem.mem[idx]))
435	  end
436	  `uvm_info("FINAL_CHECK", "Memory check pass.", UVM_LOW)
437	
438	  // Queue check
439	  if(rt_queue_rvs.size()>0) begin
440	    `uvm_error("FINAL_CHECK", "rt_queue_rvs wasn't empty!")
441	    foreach(rt_queue_rvs[idx]) begin
442	      `uvm_error("FINAL_CHECK",rt_queue_rvs[idx].sprint())
443	    end
444	  end
445	  if(rt_queue_mdl.size()>0) begin
446	    `uvm_error("FINAL_CHECK", "rt_queue_mdl wasn't empty!")
447	    foreach(rt_queue_mdl[idx]) begin
448	      `uvm_error("FINAL_CHECK",rt_queue_mdl[idx].sprint())
449	    end
450	  end
451	  if(vrf_queue_rvs.size()>0) begin
452	    `uvm_error("FINAL_CHECK", "vrf_queue_rvs wasn't empty!")
453	    foreach(vrf_queue_rvs[idx]) begin
454	      `uvm_error("FINAL_CHECK",vrf_queue_rvs[idx].sprint())
455	    end
456	  end
457	  if(vrf_queue_mdl.size()>0) begin
458	    `uvm_error("FINAL_CHECK", "vrf_queue_mdl wasn't empty!")
459	    foreach(vrf_queue_mdl[idx]) begin
460	      `uvm_error("FINAL_CHECK",vrf_queue_mdl[idx].sprint())
461	    end
462	  end
463	
464	  // Executed inst num check
465	  if(rvv_executed_inst !== mdl_executed_inst) begin
466	    `uvm_error("FINAL_CHECK", "Executed instruction number mismatch.")
467	  end
468	  `uvm_info(get_type_name(),"Exit final_phase...", UVM_HIGH)
469	endfunction: final_phase
470	`endif // RVV_SCOREBOARD__SV
